// Busca fuzzy + retorna TODOS os resultados relevantes (com e sem estoque)
// para que o agente possa raciocinar sobre alternativas e enviar fotos.

const payload = $input.first().json;
const docs = payload.documents || [];
const searchTerm = $('Workflow Trigger').first().json.search_term || '';
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const searchWords = norm(searchTerm).split(/\s+/).filter(w => w.length > 1);

const sizeWords = new Set(['pp','p','m','g','gg','xg','xxg','xs','s','l','xl','xxl']);
const isNumericSize = (w) => /^\d{1,3}$/.test(w);

function parseValue(val) {
  if (!val) return null;
  if (val.stringValue !== undefined) return val.stringValue;
  if (val.integerValue !== undefined) return Number(val.integerValue);
  if (val.doubleValue !== undefined) return Number(val.doubleValue);
  if (val.booleanValue !== undefined) return val.booleanValue;
  if (val.timestampValue !== undefined) return val.timestampValue;
  if (val.nullValue !== undefined) return null;
  if (val.arrayValue) return (val.arrayValue.values || []).map(v => parseValue(v));
  if (val.mapValue) {
    const obj = {};
    for (const [k, v] of Object.entries(val.mapValue.fields || {})) obj[k] = parseValue(v);
    return obj;
  }
  return JSON.stringify(val);
}

const products = docs.map((doc) => {
  const product = { sku: doc.name?.split('/').pop() || '' };
  for (const [key, val] of Object.entries(doc.fields || {})) {
    product[key] = parseValue(val);
  }

  const imageUrls = Array.isArray(product.image_urls)
    ? product.image_urls.filter(Boolean)
    : product.image_url
      ? [product.image_url]
      : [];

  return {
    ...product,
    image_urls: imageUrls,
    image_url: imageUrls[0] || product.image_url || ''
  };
}).filter((product) => product.is_active !== false);

if (products.length === 0) {
  return [{ json: { found: false, message: 'Nenhum produto encontrado.' } }];
}

if (searchWords.length === 0) {
  const available = products.filter(p => (p.stock || 0) > 0);
  return available.slice(0, 15).map(p => ({
    json: {
      found: true,
      name: p.name,
      color: p.color || '',
      size: p.size || '',
      price: p.price,
      stock: p.stock,
      description: p.description || '',
      category: p.category || '',
      image_url: p.image_url || '',
      image_urls: p.image_urls || []
    }
  }));
}

const productWords = [];
let searchedSize = null;
const colorWords = [];

const knownColors = ['preto','branco','azul','vermelho','verde','amarelo','rosa','roxo','laranja','marrom','cinza','bege','dourado','prata','nude','caramelo','vinho','bordo','coral','lilas','turquesa','creme','grafite','off-white','offwhite'];

for (const word of searchWords) {
  if (sizeWords.has(word) || isNumericSize(word)) {
    searchedSize = word;
  } else if (knownColors.includes(word)) {
    colorWords.push(word);
  } else {
    productWords.push(word);
  }
}

function searchable(p) {
  const tagsStr = Array.isArray(p.tags) ? p.tags.join(' ') : (p.tags || '');
  return norm([p.name || '', p.description || '', p.category || '', tagsStr].join(' '));
}

const scored = products.map(p => {
  const text = searchable(p);
  const nameNorm = norm(p.name);
  let score = 0;

  for (const word of productWords) {
    if (text.includes(word)) score += 10;
    for (const w of text.split(/\s+/)) {
      if (w.startsWith(word) || word.startsWith(w)) score += 3;
    }
  }
  if (productWords.length > 0 && nameNorm.includes(productWords.join(' '))) score += 25;
  if (norm(p.category) === productWords.join(' ')) score += 15;
  if (Array.isArray(p.tags) && p.tags.some(t => productWords.some(pw => norm(t).includes(pw)))) score += 10;

  let colorMatch = colorWords.length === 0 ? null : false;
  if (colorWords.length > 0 && p.color) {
    if (colorWords.some(c => norm(p.color).includes(c))) {
      colorMatch = true;
      score += 15;
    }
  }

  let sizeMatch = searchedSize === null ? null : false;
  if (searchedSize && p.size !== undefined && p.size !== null) {
    if (norm(String(p.size)) === searchedSize) {
      sizeMatch = true;
      score += 15;
    }
  }

  return {
    sku: p.sku,
    name: p.name,
    color: p.color || '',
    size: p.size !== undefined ? p.size : '',
    price: p.price,
    stock: p.stock || 0,
    description: p.description || '',
    category: p.category || '',
    image_url: p.image_url || '',
    image_urls: p.image_urls || [],
    _score: score,
    _colorMatch: colorMatch,
    _sizeMatch: sizeMatch,
    _inStock: (p.stock || 0) > 0
  };
});

const relevant = scored.filter(p => p._score > 0).sort((a, b) => b._score - a._score);

if (relevant.length === 0) {
  return [{ json: { found: false, message: 'Nenhum produto encontrado para: ' + searchTerm } }];
}

const exact = relevant.filter(p => 
  p._inStock && 
  (p._colorMatch === null || p._colorMatch === true) && 
  (p._sizeMatch === null || p._sizeMatch === true)
);

const sameProductDiffColor = relevant.filter(p => 
  p._inStock && 
  p._colorMatch === false && 
  (p._sizeMatch === null || p._sizeMatch === true)
);

const sameProductDiffSize = relevant.filter(p => 
  p._inStock && 
  (p._colorMatch === null || p._colorMatch === true) && 
  p._sizeMatch === false
);

const outOfStock = relevant.filter(p => 
  !p._inStock && 
  (p._colorMatch === null || p._colorMatch === true) && 
  (p._sizeMatch === null || p._sizeMatch === true)
);

const stripInternal = ({ _score, _colorMatch, _sizeMatch, _inStock, ...product }) => product;
const result = { found: true };

if (exact.length > 0) {
  result.exact_matches = exact.slice(0, 5).map(stripInternal);
}
if (sameProductDiffColor.length > 0) {
  result.alternative_colors = sameProductDiffColor.slice(0, 5).map(stripInternal);
}
if (sameProductDiffSize.length > 0) {
  result.alternative_sizes = sameProductDiffSize.slice(0, 5).map(stripInternal);
}
if (outOfStock.length > 0) {
  result.out_of_stock = outOfStock.slice(0, 3).map(stripInternal);
}

if (!result.exact_matches && !result.alternative_colors && !result.alternative_sizes) {
  result.found = false;
  result.message = 'Produto não encontrado com essas especificações.';
  if (outOfStock.length > 0) result.message += ' Estava no catálogo mas zerou o estoque.';
}

return [{ json: result }];
